class AutocompleteSystem:
    def solve(self, sentences: List[str], times: List[int]):
        self.trie = {}
        self.cur_node = self.trie
        self.cur_str = ''
        for s, t in zip(sentences, times): self.insert(s, t)
    def insert(self, s, t):
        node = self.trie
        for c in s:
            if c not in node: node[c] = {'_data': collections.defaultdict(int)}
            node = node[c]
            node['_data'][s] += t
    def input(self, c: str) -> List[str]:
        if c == '#':
            self.insert(self.cur_str, 1)
            self.cur_str = ''
            self.cur_node = self.trie
            return []
        self.cur_str += c
        if self.cur_node and c in self.cur_node:
            self.cur_node = self.cur_node[c]
            data = self.cur_node['_data']
            res = sorted(data.items(), key=lambda x: (-x[1], x[0]))
            return [r[0] for r in res[:3]]
        self.cur_node = None
        return []

